#include <bits/stdc++.h>
using namespace std;

int solve(int n) {
    vector<int> dp(n + 1);

    // Base case: fill with number of A's possible by just pressing A
    for(int i = 0; i <= n; i++) {
        dp[i] = i;
    }

    // For each length
    for(int i = 3; i <= n; i++) {
        // Try breaking at different positions
        for(int j = 2; j < i - 1; j++) {
            // dp[j-1] represents A's before break
            // (i-j) represents number of times we can paste
            dp[i] = max(dp[i], dp[j-1] * (i-j));
        }
    }

    return dp[n];
}

int main() {
    int t;
    cin >> t;
    while(t--) {
        int n;
        cin >> n;
        cout << solve(n) << endl;
    }
    return 0;
}

